class LogHTTPServer(HTTPServer):
    def __init__(self, server_address, RequestHandlerClass, log_file_path):
        super().__init__(server_address, RequestHandlerClass)
        self.log_file_path = log_file_path
        self._setup_initial_logging()

    def _setup_initial_logging(self):
        # Ensure the log directory exists
        log_dir = os.path.dirname(self.log_file_path)
        if log_dir and not os.path.exists(log_dir):
            os.makedirs(log_dir)
        # Touch the file to ensure it's writable and exists
