def run_server(host='0.0.0.0', port=8080, log_file='app.log'):
    server_address = (host, port)
    httpd = LogHTTPServer(server_address, LoggingHTTPHandler, log_file)
    print(f"Starting centralized logging server on {host}:{port}")
    print(f"All logs will be written to: {os.path.abspath(log_file)}")
    try:
        httpd.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down the server.")
        httpd.server_close()

